for (const [pageNum, qList] of sortedPages) {
  console.log(`[SURGERY] Processing Page ${pageNum}...`);

  // Targeted Regex: Find the section with Page X label, then look for its text-container div
  const pageRegex = new RegExp(`aria-label\\s*=\\s*["']Page\\s+${pageNum}["'][\\s\\S]*?<div class=["']text-container["']>`, "i");
  const match = html.match(pageRegex);

  if (match && match.index !== undefined) {
    const insertIdx = match.index + match[0].length;
    const dataPayload = JSON.stringify(qList);

    // Added visible markers for easier dev-tool debugging in iframe
    const injection = `\n<!-- MIRON_INJECT_START_PG_${pageNum} -->\n<div class="miron-challenge-anchor" data-questions='${dataPayload.replace(/'/g, "&apos;")}'></div>\n<!-- MIRON_INJECT_END -->\n`;

    // APPLY THE INJECTION ONCE (Fixes double-injection bug)
    html = html.slice(0, insertIdx) + injection + html.slice(insertIdx);
    console.log(`[LOG] SUCCESS: Injected questions into Page ${pageNum} text-container (Index: ${insertIdx})`);
  } else {
     console.error(`[CRITICAL] FAILED to find text-container for Page ${pageNum}. Regex failed.`);
     // Fallback: search for page-container if text-container doesn't exist
     const fallbackRegex = new RegExp(`aria-label\\s*=\\s*["']Page\\s+${pageNum}["']`, "i");
     const fallbackMatch = html.match(fallbackRegex);
     if (fallbackMatch) {
       const endOfTagIdx = html.indexOf(">", fallbackMatch.index) + 1;
       const dataPayload = JSON.stringify(qList);
       const injection = `<div class="miron-challenge-anchor" data-questions='${dataPayload.replace(/'/g, "&apos;")}'></div>`;
       html = html.slice(0, endOfTagIdx) + injection + html.slice(endOfTagIdx);
       console.log(`[LOG] WARNING: Used fallback injection for Page ${pageNum}`);
     }
  }

